--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1475,8 +1475,69 @@ static Instruction *factorizeMathWithShlOps(BinaryOperator &I,
   return NewShl;
 }

-/// Reduce a sequence of masked half-width multiplies to a single multiply.
-/// ((XLow * YHigh) + (YLow * XHigh)) << HalfBits) + (XLow * YLow) --> X * Y
+/// Fold ceiling division pattern:
+/// (X >> K) + zext(icmp ne (and(X, (1<<K)-1), 0)) --> (X + ((1<<K)-1)) >> K
+/// This is equivalent to ceil(X / 2^K) = (X + 2^K - 1) >> K
+/// This transformation is only valid when X + ((1<<K)-1) doesn't overflow.
+static Instruction *foldCeilDivPattern(BinaryOperator &Add,
+                                        InstCombiner::BuilderTy &Builder) {
+  Value *Op0 = Add.getOperand(0), *Op1 = Add.getOperand(1);
+  Type *Ty = Add.getType();
+  
+  Value *X, *X2;
+  const APInt *ShAmt;
+  
+  // Match: add(lshr(X, K), zext(icmp ne (and(X, (1<<K)-1), 0)))
+  if (match(Op0, m_LShr(m_Value(X), m_APInt(ShAmt))) &&
+      match(Op1, m_ZExt(m_SpecificICmp(ICmpInst::ICMP_NE,
+                                       m_Value(X2), m_Zero())))) {
+    const APInt *Mask;
+    if (match(X2, m_And(m_Specific(X), m_APInt(Mask)))) {
+      APInt ExpectedMask = APInt::getLowBitsSet(Ty->getScalarSizeInBits(),
+                                                 ShAmt->getZExtValue());
+      if (*Mask == ExpectedMask) {
+        // Check that X + mask doesn't overflow using KnownBits analysis
+        KnownBits Known = computeKnownBits(X, &Add);
+        APInt MaxVal = Known.getMaxValue();
+        APInt MaxRepresentable = APInt::getMaxValue(Ty->getScalarSizeInBits());
+        // Check if MaxVal + ExpectedMask would overflow
+        if (MaxVal.ugt(MaxRepresentable - ExpectedMask))
+          return nullptr;
+        auto *NewAdd = cast<BinaryOperator>(Builder.CreateNUWAdd(
+            X, ConstantInt::get(Ty, ExpectedMask), "ceil.add"));
+        NewAdd->setHasNoSignedWrap(Add.hasNoSignedWrap());
+        return BinaryOperator::CreateLShr(
+            NewAdd, ConstantInt::get(Ty, *ShAmt));
+      }
+    }
+  }
+  
+  // Try commuted case: add(zext(icmp ne ...), lshr(X, K))
+  if (match(Op1, m_LShr(m_Value(X), m_APInt(ShAmt))) &&
+      match(Op0, m_ZExt(m_SpecificICmp(ICmpInst::ICMP_NE,
+                                       m_Value(X2), m_Zero())))) {
+    const APInt *Mask;
+    if (match(X2, m_And(m_Specific(X), m_APInt(Mask)))) {
+      APInt ExpectedMask = APInt::getLowBitsSet(Ty->getScalarSizeInBits(),
+                                                 ShAmt->getZExtValue());
+      if (*Mask == ExpectedMask) {
+        KnownBits Known = computeKnownBits(X, &Add);
+        APInt MaxVal = Known.getMaxValue();
+        APInt MaxRepresentable = APInt::getMaxValue(Ty->getScalarSizeInBits());
+        if (MaxVal.ugt(MaxRepresentable - ExpectedMask))
+          return nullptr;
+        auto *NewAdd = cast<BinaryOperator>(Builder.CreateNUWAdd(
+            X, ConstantInt::get(Ty, ExpectedMask), "ceil.add"));
+        NewAdd->setHasNoSignedWrap(Add.hasNoSignedWrap());
+        return BinaryOperator::CreateLShr(
+            NewAdd, ConstantInt::get(Ty, *ShAmt));
+      }
+    }
+  }
+  
+  return nullptr;
+}
+
 static Instruction *foldBoxMultiply(BinaryOperator &I) {
   unsigned BitWidth = I.getType()->getScalarSizeInBits();
   // Skip the odd bitwidth types.
@@ -1547,9 +1608,10 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
   if (Instruction *X = foldNoWrapAdd(I, Builder))
     return X;

-  if (Instruction *R = foldBinOpShiftWithShift(I))
+  if (Instruction *R = foldCeilDivPattern(I, Builder))
     return R;

+  if (Instruction *R = foldBinOpShiftWithShift(I))
   if (Instruction *R = combineAddSubWithShlAddSub(Builder, I))
     return R;

