static Instruction *foldCeilDivPattern(BinaryOperator &Add,
                                        InstCombiner::BuilderTy &Builder) {
  Value *Op0 = Add.getOperand(0), *Op1 = Add.getOperand(1);
  Type *Ty = Add.getType();

  Value *X, *X2;
  const APInt *ShAmt;
  ICmpInst::Predicate Pred;

  // Match: add(lshr(X, K), zext(icmp ne (and(X, (1<<K)-1), 0)))
  if (match(Op0, m_LShr(m_Value(X), m_APInt(ShAmt))) &&
      match(Op1, m_OneUse(m_ZExt(m_SpecificICmp(ICmpInst::ICMP_NE,
                                                 m_Value(X2), m_Zero()))))) {
    // Check that the icmp operand is (X & mask)
    const APInt *Mask;
    if (match(X2, m_And(m_Specific(X), m_APInt(Mask)))) {
      // Verify mask == (1 << K) - 1
      APInt ExpectedMask = APInt::getLowBitsSet(Ty->getScalarSizeInBits(),
                                                 ShAmt->getZExtValue());
      if (*Mask == ExpectedMask) {
        auto *NewAdd = cast<BinaryOperator>(Builder.CreateNUWAdd(
            X, ConstantInt::get(Ty, ExpectedMask), "ceil.add"));
        NewAdd->setHasNoSignedWrap(Add.hasNoSignedWrap());
        return BinaryOperator::CreateLShr(
            NewAdd, ConstantInt::get(Ty, *ShAmt));
      }
    }
  }

  // Try commuted case: add(zext(icmp ne ...), lshr(X, K))
  if (match(Op1, m_LShr(m_Value(X), m_APInt(ShAmt))) &&
      match(Op0, m_OneUse(m_ZExt(m_SpecificICmp(ICmpInst::ICMP_NE,
                                                 m_Value(X2), m_Zero()))))) {
    const APInt *Mask;
    if (match(X2, m_And(m_Specific(X), m_APInt(Mask)))) {
      APInt ExpectedMask = APInt::getLowBitsSet(Ty->getScalarSizeInBits(),
                                                 ShAmt->getZExtValue());
      if (*Mask == ExpectedMask) {
        auto *NewAdd = cast<BinaryOperator>(Builder.CreateNUWAdd(
            X, ConstantInt::get(Ty, ExpectedMask), "ceil.add"));
        NewAdd->setHasNoSignedWrap(Add.hasNoSignedWrap());
        return BinaryOperator::CreateLShr(
            NewAdd, ConstantInt::get(Ty, *ShAmt));
      }
    }
  }

  return nullptr;
}
